_DATA = None

def _load():
    global _DATA
    if _DATA is None:
        _DATA = json.loads(gzip.decompress(base64.b64decode(_BLOB)))
    return _DATA

def units():
    return _load()['units']


def _decode_ring(s, quant=1000):
    out = []
    lon = lat = i = 0
    n = len(s)
    while i < n:
        for k in range(2):
            result = shift = 0
            while True:
                b = ord(s[i]) - 63; i += 1
                result |= (b & 0x1f) << shift
                shift += 5
                if b < 0x20:
                    break
            delta = ~(result >> 1) if (result & 1) else (result >> 1)
            if k == 0:
                lon += delta
            else:
                lat += delta
        out.append((lon / quant, lat / quant))
    return out


def _ring_contains(ring, lat, lon):
    inside = False
    n = len(ring)
    j = n - 1
    for i in range(n):
        xi, yi = ring[i]
        xj, yj = ring[j]
        if ((yi > lat) != (yj > lat)) and \
           (lon < (xj - xi) * (lat - yi) / ((yj - yi) or 1e-9) + xi):
            inside = not inside
        j = i
    return inside


_RINGS = None

def _rings():
    global _RINGS
    if _RINGS is None:
        _RINGS = []
        for e in _load()['enc']:
            bb = e['b']
            area = (bb[2] - bb[0]) * (bb[3] - bb[1])
            _RINGS.append((e['i'], bb, area, [_decode_ring(r) for r in e['r']]))
    return _RINGS


def unit_at(lat, lon):
    """Return admin_uid of the smallest ADM1 unit containing the point, or None."""
    best, best_area = None, 1e18
    for uid, bb, area, rings in _rings():
        if lon < bb[0] or lon > bb[2] or lat < bb[1] or lat > bb[3]:
            continue
        for ring in rings:
            if _ring_contains(ring, lat, lon):
                if area < best_area:
                    best_area, best = area, uid
                break
    return best
